import request from './request'

export function login(data) {
  return request({
    url: '/auth/login',
    method: 'post',
    data
  })
}

export function register(data) {
  return request({
    url: '/auth/register',
    method: 'post',
    data
  })
}

export function getUserInfo() {
  return request({
    url: '/auth/info',
    method: 'get'
  })
}

export function updatePassword(data) {
  return request({
    url: '/auth/password',
    method: 'put',
    params: data
  })
}

export function updateUserInfo(data) {
  return request({
    url: '/auth/info',
    method: 'put',
    params: data
  })
}

export function logout() {
  return request({
    url: '/auth/logout',
    method: 'post'
  })
}
